<svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="28" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">BTC vs ETH Spot ETF Daily Net Flow (Jul 7-9, $M)</text>
  <rect x="550" y="14" width="14" height="14" fill="#fbbf24"/>
  <text x="568" y="25" fill="#e4e4e7" font-family="sans-serif" font-size="13">BTC ETF</text>
  <rect x="550" y="32" width="14" height="14" fill="#818cf8"/>
  <text x="568" y="43" fill="#e4e4e7" font-family="sans-serif" font-size="13">ETH ETF</text>
  <line x1="80" y1="220" x2="650" y2="220" stroke="#3f3f46" stroke-width="1.5"/>
  <text x="72" y="224" fill="#71717a" font-family="sans-serif" font-size="13" text-anchor="end">$0</text>
  <rect x="132" y="105.8" width="34" height="114.2" fill="#fbbf24"/>
  <text x="149" y="98" fill="#fbbf24" font-family="sans-serif" font-size="13" font-weight="700" text-anchor="middle">+$253.7M</text>
  <rect x="174" y="210.5" width="34" height="9.5" fill="#818cf8"/>
